INSERT INTO public.chapters (id, subject_id, title, description, lesson_content, summary, display_order) VALUES
  ('f87e1433-a97b-588e-a102-5116c2cc2d6c', 'arabic-2eme', 'فهم النصّ القصير', 'نقرأ نصًّا قصيرًا، ثمّ نجيب عن أسئلة: مَن البطل؟ وماذا فعل؟ وأين؟ ومتى؟ فنفهم القصّة ونجد الجواب في النصّ لا من خيالنا.', '# 📖 فهم النصّ القصير — أقرأ القصّة وأعرف ما فيها

> 💡 «لا أُجيب من رأسي… أُجيب ممّا قرأتُ في النصّ!»

عندما نقرأ قصّةً صغيرة، لا نكتفي بقراءة الكلمات. نحن نريد أن **نفهم** ماذا حدث. لذلك نسأل النصّ أسئلةً صغيرة، ونبحث عن الجواب **داخل** النصّ. هيّا نتعلّم الطريقة.

## 🧭 أربعة أسئلةٍ سحريّة

بعد قراءة النصّ، نسأل أربعة أسئلة:

- **مَن؟** ← مَن هي *الشخصيّة* (البطل في القصّة)؟
- **ماذا فعل؟** ← ما هو *الحدث* الذي حصل؟
- **أين؟** ← ما هو *المكان* الذي حدث فيه؟
- **متى؟** ← ما هو *الزمن* (صباحًا، مساءً، يوم العطلة…)؟

كلّ جوابٍ **مكتوبٌ في النصّ**. مهمّتنا أن نجده.

## 📚 نقرأ النصّ كاملًا أوّلًا

قبل الأسئلة، نقرأ النصّ **مرّةً كاملة** بهدوء. ثمّ نعود إليه كلّما أردنا جوابًا. لا بأس أن نقرأه **مرّتين**!

*مثال على نصٍّ قصير:*

> ذهبَ سامي إلى الحديقة. لعبَ بالكرة مع صديقه. ثمّ عادَ إلى البيت.

## 🔎 نطبّق الأسئلة على النصّ

ننظر إلى النصّ، ونملأ هذا الجدول بالجواب **من النصّ**:

| السؤال | الجواب من النصّ |
| --- | --- |
| مَن البطل؟ | **سامي** |
| ماذا فعل؟ | **لعبَ بالكرة** |
| أين؟ | **في الحديقة** |
| مع مَن؟ | **مع صديقه** |
| ماذا فعل في الآخر؟ | **عادَ إلى البيت** |

انظر: كلّ جوابٍ موجودٌ في كلماتِ النصّ. لم نخترع شيئًا من عندنا.

## 🌳 صورة القصّة

هذا سامي يلعب بالكرة في الحديقة:

<svg viewBox="0 0 140 100" xmlns="http://www.w3.org/2000/svg">
  <rect x="0" y="78" width="140" height="22" fill="#86efac" stroke="#1f2937" stroke-width="2"/>
  <g stroke="#1f2937" stroke-width="2">
    <path d="M28 78 L28 50" stroke="#92400e" stroke-width="4"/>
    <circle cx="28" cy="40" r="16" fill="#22c55e"/>
    <circle cx="92" cy="34" r="9" fill="#fde047"/>
    <circle cx="100" cy="58" r="9" fill="#fff" />
    <path d="M100 49 a9 9 0 0 1 0 18 z" fill="#ef4444"/>
    <circle cx="74" cy="44" r="6" fill="#fcd34d"/>
    <path d="M74 50 L74 66" stroke="#2563eb" stroke-width="4"/>
    <path d="M74 54 L66 62 M74 54 L82 62" />
    <path d="M74 66 L68 78 M74 66 L80 78" />
  </g>
</svg>

## 🗡️ حِيلة سريعة

إذا لم تتذكّر الجواب، **ارجع إلى النصّ واقرأه مرّةً أخرى** بأصابعك على الكلمات. الجواب يختبئ هناك، ولا يختبئ في رأسك!

## ⚠️ الفخّ الشائع

> الخطأ الشائع: **الإجابة من الخيال لا من النصّ.** قد تظنّ أنّ سامي لعبَ بالدرّاجة لأنّك تحبّ الدرّاجة… لكن النصّ قال **«بالكرة»**! نجيب دائمًا بما **في النصّ**، لا بما نتخيّله.

## 🏆 أحسنت!

> صرتَ تعرف الطريقة: اقرأ النصّ كاملًا، ثمّ اسأل **مَن؟ ماذا فعل؟ أين؟ متى؟** وابحث عن الجواب **في الكلمات**. في الفصل القادم نُثري مفرداتنا بكلماتٍ جديدة!', '# 📜 ملخّص: فهم النصّ القصير

- **نقرأ النصّ كاملًا أوّلًا** بهدوء، ولا بأس أن نقرأه مرّتين.
- نسأل أربعة أسئلة: **مَن؟** (الشخصيّة) و**ماذا فعل؟** (الحدث) و**أين؟** (المكان) و**متى؟** (الزمن).
- **كلّ جوابٍ مكتوبٌ في النصّ**، ومهمّتنا أن نجده في الكلمات.
- إذا نسينا الجواب، **نرجع إلى النصّ ونقرأه مرّةً أخرى**.
- **القاعدة الذهبيّة:** نجيب بما **في النصّ**، لا بما نتخيّله في رأسنا.', 5)
ON CONFLICT (id) DO UPDATE SET
  subject_id = EXCLUDED.subject_id,
  title = EXCLUDED.title,
  description = EXCLUDED.description,
  lesson_content = EXCLUDED.lesson_content,
  summary = EXCLUDED.summary,
  display_order = EXCLUDED.display_order;

INSERT INTO public.chapters (id, subject_id, title, description, lesson_content, summary, display_order) VALUES
  ('b7e048c2-5a28-56e0-9e3e-aa5a1aeaf88f', 'arabic-2eme', 'إثراء المفردات', 'نُثري كلماتنا حول العائلة والمدرسة والحيوانات والألوان والفواكه والجسم، ونتعلّم المجموعة التي تنتمي إليها كلّ كلمة، والمضادّ البسيط (كبير/صغير) والمترادف البسيط (فرِح/سعيد).', '# 🎨 إثراء المفردات — كلماتٌ كثيرة في جُعبتي

> 💡 «كلّما عرفتَ كلماتٍ أكثر، صار كلامُك أجمل وفهمُك أسرع!»

كلّ يومٍ نتعلّم **كلماتٍ جديدة**. الكلمات تحبّ أن تعيش في **مجموعات**: كلمات العائلة معًا، وكلمات الألوان معًا، وكلمات الفواكه معًا. هيّا نُثري جُعبتنا!

## 👨‍👩‍👧 كلمات العائلة

في البيت أشخاصٌ نحبّهم، ولكلٍّ منهم **اسم**: **أب، أمّ، أخ، أخت، جَدّ، جَدّة**.

*مثال: الأب والأمّ هما الوالدان، والجَدّ والجَدّة والدا الأب أو الأمّ.*

كلّ هذه الكلمات تنتمي إلى مجموعةٍ واحدة اسمها **العائلة**.

## 🌈 كلمات الألوان

حولنا ألوانٌ جميلة، ولكلِّ لونٍ **اسم**: **أحمر، أزرق، أخضر، أصفر**.

انظر هذه الأشكال الملوّنة، تحت كلِّ شكلٍ اسمُ لونه:

<svg viewBox="0 0 260 90" xmlns="http://www.w3.org/2000/svg">
  <g stroke="#1f2937" stroke-width="2">
    <circle cx="35" cy="35" r="22" fill="#ef4444"/>
    <rect x="78" y="13" width="44" height="44" fill="#3b82f6"/>
    <path d="M165 13 L187 57 L143 57 Z" fill="#22c55e"/>
    <path d="M225 13 l6 16 l17 0 l-14 11 l6 17 l-15 -11 l-15 11 l6 -17 l-14 -11 l17 0 z" fill="#facc15"/>
  </g>
  <g font-size="13" text-anchor="middle" fill="#1f2937">
    <text x="35" y="80">أحمر</text>
    <text x="100" y="80">أزرق</text>
    <text x="165" y="80">أخضر</text>
    <text x="230" y="80">أصفر</text>
  </g>
</svg>

## 🍎 كلمات الفواكه والخضر

نأكل فواكه لذيذة: **تفّاحة، موز، برتقالة**. وهذه موزةٌ صفراء:

<svg viewBox="0 0 110 80" xmlns="http://www.w3.org/2000/svg">
  <g stroke="#1f2937" stroke-width="2">
    <path d="M20 25 q8 40 55 42 q22 -2 18 -12 q-8 6 -22 4 q-34 -6 -44 -38 z" fill="#facc15"/>
    <path d="M20 25 q-3 -6 4 -8 q3 5 -1 9 z" fill="#a16207"/>
  </g>
</svg>

التفّاحة والموز والبرتقالة كلّها تنتمي إلى مجموعة **الفواكه**.

## 🔁 المضادّ البسيط

بعض الكلمات لها **ضِدّ** (عكسٌ في المعنى). الضدّ هو **عكس** الكلمة:

| كلمة | ضدّها |
| --- | --- |
| كبير | صغير |
| طويل | قصير |
| فوق | تحت |
| نهار | ليل |

*مثال: الفيل **كبير**، والنملة **صغيرة**؛ النهار فيه شمس، والليل فيه قمر.*

## 🌗 المترادف البسيط

وبعض الكلمات لها **مرادف** (كلمةٌ أخرى **بنفس المعنى**):

| كلمة | مرادفها |
| --- | --- |
| فرِح | سعيد |
| جميل | حسن |

*مثال: «الطفل فرِح» تعني نفس «الطفل سعيد»؛ والوردة **جميلة** تعني **حسنة**.*

> 🗡️ حِيلة سريعة: لتتذكّر كلمةً جديدة، ضعها في **مجموعتها**. كلمة «برتقالة»؟ ← مجموعة **الفواكه**. كلمة «أخت»؟ ← مجموعة **العائلة**.

> ⚠️ الفخّ الشائع: لا تخلط بين **المضادّ** و**المرادف**! المضادّ **عكس** المعنى (كبير ≠ صغير)، والمرادف **نفس** المعنى (فرِح = سعيد).

> 🏆 أحسنت! صرتَ تعرف كلمات العائلة والألوان والفواكه، وتميّز المضادّ من المرادف. جُعبتُك امتلأت بالكلمات الجميلة!', '# 📜 ملخّص: إثراء المفردات

- **الكلمات تعيش في مجموعات:** العائلة (أب، أمّ، أخ، أخت، جَدّ، جَدّة)، الألوان (أحمر، أزرق، أخضر، أصفر)، الفواكه (تفّاحة، موز، برتقالة).
- **المضادّ** هو **عكس** الكلمة في المعنى: كبير ≠ صغير، طويل ≠ قصير، فوق ≠ تحت، نهار ≠ ليل.
- **المترادف** كلمةٌ أخرى **بنفس** المعنى: فرِح = سعيد، جميل = حسن.
- **لا تخلط:** المضادّ عكسٌ، والمرادف نفس المعنى.
- **الكلمة الدخيلة** هي التي لا تنتمي للمجموعة (مثل «أحمر» وسط الفواكه).
- **القاعدة:** لتتذكّر كلمةً، ضعها في مجموعتها الصحيحة.', 6)
ON CONFLICT (id) DO UPDATE SET
  subject_id = EXCLUDED.subject_id,
  title = EXCLUDED.title,
  description = EXCLUDED.description,
  lesson_content = EXCLUDED.lesson_content,
  summary = EXCLUDED.summary,
  display_order = EXCLUDED.display_order;

INSERT INTO public.chapters (id, subject_id, title, description, lesson_content, summary, display_order) VALUES
  ('b89d1309-918b-51ff-828d-2f59d1e79e08', 'arabic-2eme', 'تركيب الجملة وترتيبها', 'نتعلّم أنّ الجملة مجموعةُ كلماتٍ مرتّبةٍ تعطي معنًى مفيدًا وتنتهي بنقطة، فنرتّب الكلمات المبعثرة ونكمّل الجملة بالكلمة الناقصة ونميّز الجملة المفيدة من غيرها.', '# 🧩 تركيب الجملة وترتيبها — كلماتٌ تقف في صفٍّ فتُعطي معنًى

> 💡 «الكلمات وحدها مبعثرة… رتّبها في صفٍّ صحيح فتصير جملةً تفهمها!»

عندما نضع **كلماتٍ** بجانب بعضها بالترتيب الصحيح، تتكوّن **جملةٌ مفيدة** تعطينا معنًى نفهمه. هيّا نتعلّم كيف نرتّب الكلمات ونكمّلها.

## 🧱 الجملة مجموعة كلماتٍ مرتّبة

**الجملة** هي مجموعةُ كلماتٍ مرتّبةٍ تعطي **معنًى مفيدًا**. كلمةٌ واحدةٌ لا تكفي؛ نحتاج عدّة كلماتٍ في صفٍّ صحيح.

نقرأ الجملة ونكتبها **من اليمين إلى اليسار**.

*مثال مرتّب: «يلعبُ الولدُ بالكرةِ.» — فهمنا المعنى: ولدٌ يلعب.*

## 🔢 نرتّب الكلمات المبعثرة

أحيانًا تكون الكلمات **مبعثرة**، فنعيد ترتيبها لتُكوّن جملةً صحيحة. تبدأ الجملة عادةً بـ**فعلٍ** (مثل: يلعبُ، تأكلُ) أو بـ**اسمٍ** (مثل: القطّةُ، البنتُ).

| كلماتٌ مبعثرة | الجملة المرتّبة |
| --- | --- |
| الكرةِ / الولدُ / يلعبُ / بـ | يلعبُ الولدُ بالكرةِ. |
| التفّاحةَ / البنتُ / تأكلُ | تأكلُ البنتُ التفّاحةَ. |
| في الحديقةِ / تجري / القطّةُ | تجري القطّةُ في الحديقةِ. |

## ✏️ نكمّل الجملة بالكلمة الناقصة

أحيانًا تنقص الجملة كلمةً، فنُكمّلها بالكلمة **المناسبة** التي تعطي معنًى:

- «تشربُ البنتُ ___.» ← نكمّلها بـ **حليبًا** (شيءٌ يُشرب).
- «يطيرُ ___ في السماءِ.» ← نكمّلها بـ **العصفورُ**.

> 🗡️ حِيلة سريعة: بعد أن ترتّب الكلمات، **اقرأ الجملة بصوتٍ عالٍ**. إذا فهمتَ المعنى، فالترتيب صحيح!

## ⏹️ الجملة تنتهي بنقطة

كلّ جملةٍ خبريّةٍ تنتهي بعلامةٍ صغيرةٍ اسمها **النقطة (.)**. النقطة تقول للقارئ: «هنا انتهت الجملة».

*مثال: تنامُ البنتُ مبكّرًا**.***

انظر هذه الصورة: ولدٌ يلعب بالكرة، تحتها الجملة المرتّبة.

<svg viewBox="0 0 160 110" xmlns="http://www.w3.org/2000/svg">
  <g stroke="#1f2937" stroke-width="2">
    <circle cx="55" cy="30" r="12" fill="#fcd34d"/>
    <path d="M55 42 L55 72" stroke="#2563eb" stroke-width="6"/>
    <path d="M55 50 L40 62 M55 50 L72 58" stroke="#2563eb" stroke-width="4"/>
    <path d="M55 72 L46 96 M55 72 L66 96" stroke="#1f2937" stroke-width="5"/>
    <circle cx="108" cy="86" r="16" fill="#ef4444"/>
    <path d="M92 86 h32 M108 70 v32" stroke="#1f2937" stroke-width="2" fill="none"/>
  </g>
</svg>

*يلعبُ الولدُ بالكرةِ.*

## 🚫 جملةٌ مفيدةٌ أم لا؟

ليست كلّ مجموعةٍ من الكلمات جملةً مفيدة. **«القطّةُ تشربُ الحليبَ.»** جملةٌ مفيدة. أمّا **«قطّةُ حليبَ تشربُ كرةِ»** فكلماتٌ مبعثرةٌ بلا ترتيبٍ ولا معنى.

> ⚠️ الفخّ الشائع: ترتيبٌ مقلوبٌ يفسد المعنى! «بالكرةِ يلعبُ الولدُ» أو «الولدُ بالكرةِ يلعبُ» يصعب فهمها؛ الأفضل أن نبدأ بالفعل: «يلعبُ الولدُ بالكرةِ.»

> 🏆 أحسنت! صرتَ ترتّب الكلمات لتُكوّن جملةً مفيدة، وتكمّلها بالكلمة الناقصة، وتختمها بنقطة. في الفصل القادم نتدرّب على الإملاء والكتابة!', '# 📜 ملخّص: تركيب الجملة وترتيبها

- **الجملة** مجموعةُ كلماتٍ **مرتّبةٍ** تعطي **معنًى مفيدًا**؛ كلمةٌ واحدةٌ لا تكفي.
- نقرأ الجملة ونرتّبها **من اليمين إلى اليسار**، وتبدأ عادةً بـ**فعلٍ** أو **اسمٍ**.
- مثالٌ مرتّب: **«يلعبُ الولدُ بالكرةِ.»**
- نُكمّل الجملة الناقصة بالكلمة **المناسبة** التي تعطي معنًى: «تأكلُ البنتُ **تفّاحةً**.»
- كلّ جملةٍ خبريّةٍ تنتهي بـ**نقطةٍ (.)** تقول: «هنا انتهت الجملة».
- **القاعدة:** اقرأ الجملة بصوتٍ عالٍ بعد ترتيبها؛ إن فهمتَ المعنى فالترتيب صحيح.', 7)
ON CONFLICT (id) DO UPDATE SET
  subject_id = EXCLUDED.subject_id,
  title = EXCLUDED.title,
  description = EXCLUDED.description,
  lesson_content = EXCLUDED.lesson_content,
  summary = EXCLUDED.summary,
  display_order = EXCLUDED.display_order;

INSERT INTO public.chapters (id, subject_id, title, description, lesson_content, summary, display_order) VALUES
  ('3bcf8fce-cfd8-5e2f-9f65-7b2bedff66d2', 'arabic-2eme', 'الإملاء والكتابة', 'نتعلّم كتابة التاء المربوطة (ة) والمفتوحة (ت) والهاء (ه)، و«ال» التعريف، والتنوين في الكتابة، وعلامات الترقيم (النقطة وعلامة الاستفهام وعلامة التعجّب)، لنكتب الكلمات والجمل كتابةً صحيحة.', '# ⚔️ الإملاء والكتابة — أكتب الكلمة صحيحةً وأضع علامتها

> 💡 «الكلمة الجميلة تُكتب صحيحةً… والجملة الجميلة تنتهي بعلامتها!»

عندما نكتب، لا يكفي أن نعرف الحروف؛ علينا أن نكتب آخر الكلمة صحيحًا، ونضع في آخر الجملة **علامةً** مناسبة. هيّا نتعلّم الإملاء وعلامات الترقيم.

## 🌸 التاء المربوطة (ة) في آخر الاسم

**التاء المربوطة** (ة) تاءٌ مستديرةٌ عليها نقطتان، تأتي في **آخر الاسم**. عند **الوقف** (التوقّف) ننطقها **هاءً**، مثل: **مَدْرَسة، تُفّاحة، وَرْدة، قِطّة**.

*مثال: نقول «هذه مَدْرَسة» وعند الوقف نسمعها «مَدْرَسهْ»، لكنّها تُكتب بالتاء المربوطة (ة).*

| الكلمة | تُكتب بـ |
| --- | --- |
| مَدْرَسة | التاء المربوطة (ة) |
| تُفّاحة | التاء المربوطة (ة) |
| وَرْدة | التاء المربوطة (ة) |

انظر هذه التفّاحة الحمراء، اسمها **تُفّاحة** يُكتب آخره بالتاء المربوطة (ة):

<svg viewBox="0 0 120 110" xmlns="http://www.w3.org/2000/svg">
  <g stroke="#1f2937" stroke-width="2">
    <path d="M40 30 q20 -16 40 0 q14 14 4 40 q-10 24 -24 24 q-14 0 -24 -24 q-10 -26 4 -40z" fill="#ef4444"/>
    <path d="M60 30 q-3 -12 6 -18" fill="none" stroke="#7c2d12" stroke-width="3"/>
    <path d="M62 22 q12 -8 18 2 q-12 4 -18 -2z" fill="#22c55e"/>
    <text x="60" y="64" font-size="13" text-anchor="middle" fill="#fff7ed" stroke="none">تُفّاحة</text>
  </g>
</svg>

## ✋ التاء المفتوحة (ت) والهاء (ه)

ليست كلّ تاءٍ مربوطة! **التاء المفتوحة** (ت) تاءٌ ممدودةٌ عليها نقطتان، ننطقها **تاءً** حتّى عند الوقف، مثل: **بِنت، بَيت، أُخت**.

وهناك **الهاء** (ه) حرفٌ بلا نقطتين، مثل: **وَجه، فَمه**. الفرق: التاء المربوطة عليها نقطتان، والهاء بلا نقطتين.

| الكلمة | الحرف الأخير |
| --- | --- |
| بِنت | التاء المفتوحة (ت) |
| بَيت | التاء المفتوحة (ت) |
| وَجه | الهاء (ه) |

## 📖 «ال» التعريف

نضع **«ال»** في أوّل الاسم لنُعرّفه، فيصير معروفًا معيَّنًا: **قَلَم ← القَلَم**، **شَمس ← الشَّمس**، **بَيت ← البَيت**. هذه الألف واللام تُسمّى **«ال» التعريف**.

*مثال: «كِتاب» اسمٌ عامّ، أمّا «الكِتاب» فهو كتابٌ نعرفه.*

## ❓ علامات الترقيم: النقطة وعلامة الاستفهام وعلامة التعجّب

في آخر الجملة نضع **علامةً** تُناسبها:

- **النقطة (.)** نضعها في آخر الجملة **الخبريّة** التي تُخبر بشيء: *ذهبَ الولدُ إلى المدرسةِ.*
- **علامة الاستفهام (؟)** نضعها في آخر **السؤال**: *هل تُحبّ القراءة؟*
- **علامة التعجّب (!)** نضعها للتعبير عن **الفرح أو الدهشة**: *ما أجملَ الحديقةَ!*

| الجملة | علامتها |
| --- | --- |
| أكلَ القطُّ السمكةَ | النقطة (.) |
| أين ذهبَ أخوك | علامة الاستفهام (؟) |
| ما أروعَ البحرَ | علامة التعجّب (!) |

> 🗡️ حِيلة سريعة: عند الوقف، إن نطقتَ آخر الكلمة **«ـه»** فهي **تاء مربوطة (ة)** مثل «مَدْرَسة»؛ وإن نطقتَها **«ـت»** فهي **تاء مفتوحة (ت)** مثل «بِنت».

> ⚠️ الفخّ الشائع: لا تكتب التاء المربوطة مكان المفتوحة! نكتب **«بِنت»** بالتاء المفتوحة لا «بِنة»، و**«بَيت»** لا «بَية». واعلم أنّ السؤال ينتهي بـ **؟** لا بالنقطة.

> 🏆 أحسنت! صرتَ تعرف التاء المربوطة (ة) والمفتوحة (ت) والهاء (ه)، و«ال» التعريف، وعلامات الترقيم. الآن تكتب كلماتك وجملك كتابةً صحيحةً جميلة!', '# 📜 ملخّص: الإملاء والكتابة

- **التاء المربوطة (ة):** تاءٌ مستديرةٌ عليها نقطتان في آخر الاسم، ننطقها هاءً عند الوقف، مثل مَدْرَسة، تُفّاحة، وَرْدة.
- **التاء المفتوحة (ت):** تاءٌ ممدودةٌ نُنطقها تاءً دائمًا، مثل بِنت، بَيت، أُخت.
- **الهاء (ه):** حرفٌ بلا نقطتين، مثل وَجه، فَمه — نميّزها من التاء المربوطة بالنقطتين.
- **«ال» التعريف:** نضعها في أوّل الاسم فيصير معرّفًا، مثل القَلَم، الشَّمس، الكِتاب.
- **علامات الترقيم:** النقطة (.) آخر الجملة الخبريّة، وعلامة الاستفهام (؟) آخر السؤال، وعلامة التعجّب (!) للفرح والدهشة.
- **القاعدة:** عند الوقف إن سمعتَ «ـه» فهي تاء مربوطة (ة)، وإن سمعتَ «ـت» فهي تاء مفتوحة (ت).', 8)
