INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('33973f94-34c2-5994-88ce-3c14d77237b9', 'bd351423-f746-5988-8100-4dbe35c94820', 'قال طفل: «إذا رأيت فجوةً داخل الكلمة فالكلمة فيها خطأ». ما الصحيح؟', '[{"id":"a","text":"صحيح، الفجوة دائمًا خطأ"},{"id":"b","text":"الفجوة طبيعيّةٌ بعد الحروف الستّة، وليست خطأ"},{"id":"c","text":"الفجوة تعني نقص حرف"},{"id":"d","text":"الكلمات لا تحوي فجواتٍ أبدًا"}]'::jsonb, 'b', 'الخطأ الشائع: ظنّ الفجوة خطأً. الفجوة بعد الحروف الستّة (أ، د، ذ، ر، ز، و) طبيعيّةٌ لأنّها لا تتّصل بما بعدها.', 5)
