INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('aa845537-63bb-5317-a475-201ff0fe782e', 'bd351423-f746-5988-8100-4dbe35c94820', 'هذه سمكة. في كلمة «سَمَكة»، أيّ حرفٍ لا يتّصل بما بعده؟<svg viewBox="0 0 120 80" xmlns="http://www.w3.org/2000/svg"><g stroke="#1f2937" stroke-width="2"><ellipse cx="55" cy="40" rx="34" ry="20" fill="#fb923c"/><path d="M89 40 l22 -14 l0 28 z" fill="#fdba74"/><circle cx="40" cy="34" r="3" fill="#1f2937" stroke="none"/><path d="M30 40 q8 6 16 0" fill="none"/><path d="M55 22 q6 8 0 8 M62 24 q6 6 0 8" fill="#fdba74"/></g></svg>', '[{"id":"a","text":"لا يوجد؛ كلّ حروف «سَمَكة» تتّصل بما بعدها"},{"id":"b","text":"السين لا تتّصل"},{"id":"c","text":"الميم لا تتّصل"},{"id":"d","text":"الكاف لا تتّصل"}]'::jsonb, 'a', 'حروف «سَمَكة» هي س، م، ك، ة وكلّها تتّصل بما بعدها، فلا حرف من الستّة فيها ولا فجوة.', 6)
