  ('d271e6dc-1e90-5bb4-9995-a3c0e83d2318', 'c11b9afc-cfef-57a7-8b0a-64cd4a5ef188', 'هذا قمرٌ في الليل. كم مقطعًا في كلمة «قَمَر»؟<svg viewBox="0 0 110 90" xmlns="http://www.w3.org/2000/svg"><g stroke="#1f2937" stroke-width="2"><rect x="0" y="0" width="110" height="90" fill="#1e3a8a" stroke="none"/><circle cx="58" cy="45" r="26" fill="#fde047"/><circle cx="68" cy="40" r="22" fill="#1e3a8a" stroke="none"/><circle cx="20" cy="18" r="2.5" fill="#fde047" stroke="none"/><circle cx="95" cy="22" r="2.5" fill="#fde047" stroke="none"/><circle cx="30" cy="70" r="2" fill="#fde047" stroke="none"/></g></svg>', '[{"id":"a","text":"مقطعٌ واحد"},{"id":"b","text":"أربعة مقاطع"},{"id":"c","text":"ثلاثة مقاطع"},{"id":"d","text":"مقطعان"}]'::jsonb, 'd', 'قَمَر = قَ‑مَر، مقطعان، لأنّ فيها حركتين: قَ ثمّ مَر.', 2)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('ce3d26ad-8ada-563d-b669-0ab779979895', 'c11b9afc-cfef-57a7-8b0a-64cd4a5ef188', 'كم مقطعًا في كلمة «تُفّاحة»؟', '[{"id":"a","text":"مقطعان"},{"id":"b","text":"ثلاثة مقاطع"},{"id":"c","text":"أربعة مقاطع"},{"id":"d","text":"مقطعٌ واحد"}]'::jsonb, 'b', 'تُفّاحة = تُفْ‑فا‑حة، ثلاثة مقاطع؛ الشدّة تجعل الفاء الأولى ساكنةً تُغلق المقطع الأوّل.', 3)
