INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('e3032d6a-0860-5995-9f9b-afcab5b9ec90', 'c11b9afc-cfef-57a7-8b0a-64cd4a5ef188', 'قال طفل: «شمسْ كلمةٌ من مقطعين». ما الصحيح؟', '[{"id":"a","text":"صحيح، فيها مقطعان"},{"id":"b","text":"صحيح، فيها ثلاثة مقاطع"},{"id":"c","text":"خطأ، «شمسْ» مقطعٌ واحد لأنّ الساكن لا يصنع مقطعًا"},{"id":"d","text":"خطأ، «شمسْ» أربعة مقاطع"}]'::jsonb, 'c', 'الفخّ: عدّ الحروف الساكنة مقاطع. «شمسْ» مقطعٌ واحد؛ لا مقطع بلا حركة، والميم والسين الساكنتان تُغلقان المقطع.', 4)
ON CONFLICT (id) DO UPDATE SET
