  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('4e4be927-a807-51aa-a4f9-a57d401140da', 'c11b9afc-cfef-57a7-8b0a-64cd4a5ef188', 'أيّ مجموعةٍ ترتيبها صحيحٌ من حيث عدد المقاطع: من الأقلّ إلى الأكثر؟', '[{"id":"a","text":"سَمَكة (1) ثمّ قَمَر (2) ثمّ بابْ (3)"},{"id":"b","text":"قَمَر (1) ثمّ بابْ (2) ثمّ سَمَكة (3)"},{"id":"c","text":"بابْ (3) ثمّ قَمَر (2) ثمّ سَمَكة (1)"},{"id":"d","text":"بابْ (1) ثمّ قَمَر (2) ثمّ سَمَكة (3)"}]'::jsonb, 'd', 'بابْ مقطعٌ واحد، وقَمَر = قَ‑مَر مقطعان، وسَمَكة = سَ‑مَ‑كة ثلاثة مقاطع، فالترتيب 1 ثمّ 2 ثمّ 3.', 5)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
