  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('248af506-ff76-58af-8221-d44bbc68e165', 'c11b9afc-cfef-57a7-8b0a-64cd4a5ef188', 'كلمتان فيهما حرف مدّ: «نورْ» و«فيلْ». ما حرف المدّ في كلٍّ منهما على الترتيب؟', '[{"id":"a","text":"الواو (و) في نورْ، والياء (ي) في فيلْ"},{"id":"b","text":"الألف (ا) في نورْ، والواو (و) في فيلْ"},{"id":"c","text":"الياء (ي) في نورْ، والألف (ا) في فيلْ"},{"id":"d","text":"النون (ن) في نورْ، والفاء (ف) في فيلْ"}]'::jsonb, 'a', 'في «نورْ» الواو تمدّ الضمّة، وفي «فيلْ» الياء تمدّ الكسرة، فحرفا المدّ هما و ثمّ ي.', 6)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
