INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('f3c912f0-f47d-5cbb-bbfb-1e42e952899c', '3e6c3389-4bbd-5f19-b40e-c1d3beb5da8c', 'ممّ يتكوّن المقطع؟', '[{"id":"a","text":"من حركتين"},{"id":"b","text":"من حرفٍ ساكنٍ وحده"},{"id":"c","text":"من حرفين بلا حركة"},{"id":"d","text":"من صامتٍ وصائت (حرفٍ وحركة)"}]'::jsonb, 'd', 'المقطع = صامتٌ + صائت، أي حرفٌ + حركة ننطقهما دفعةً واحدة، فلا مقطع بلا حركة.', 1)
