INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('6fc36f33-62aa-58ae-942a-25501b54dda0', '3e6c3389-4bbd-5f19-b40e-c1d3beb5da8c', 'قال طفل: «نورْ كلمةٌ من مقطعين لأنّ فيها واوًا وراءً». ما الصحيح؟', '[{"id":"a","text":"صحيح، فيها مقطعان"},{"id":"b","text":"خطأ، «نورْ» مقطعٌ واحد؛ الواو مدٌّ والراء ساكنةٌ تُغلق المقطع"},{"id":"c","text":"خطأ، «نورْ» ثلاثة مقاطع"},{"id":"d","text":"صحيح، كلّ حرفٍ مقطع"}]'::jsonb, 'b', 'الفخّ: عدّ حرف المدّ والساكن مقاطع. «نورْ» مقطعٌ واحد؛ الواو تمدّ الضمّة والراء الساكنة تُغلق المقطع، فلا مقطع ثانٍ.', 6)
