INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('6c6e9e6e-5e5a-5082-b73a-41dd04583a34', '8b921863-a6c4-5bd2-9a7e-e16a81c8926e', 'انظر إلى الصورة. أيّ كلمةٍ تناسبها؟<svg viewBox="0 0 110 110" xmlns="http://www.w3.org/2000/svg"><g stroke="#1f2937" stroke-width="2"><path d="M55 28 q-22 -6 -22 22 q0 30 22 38 q22 -8 22 -38 q0 -28 -22 -22" fill="#ef4444"/><path d="M55 28 q3 -10 14 -12" fill="none" stroke="#16a34a" stroke-width="3"/><path d="M55 28 q-2 -8 2 -14" fill="none" stroke="#92400e" stroke-width="3"/></g></svg>', '[{"id":"a","text":"تُفّاحة"},{"id":"b","text":"شَجَرة"},{"id":"c","text":"سَمَكة"},{"id":"d","text":"شَمْس"}]'::jsonb, 'a', 'الصورة فاكهةٌ حمراء مستديرة لها ورقةٌ خضراء وعُنيق، وهي التُّفّاحة، فالكلمة المناسبة «تُفّاحة».', 1)
