  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('4d074fc5-d369-527f-9fb0-6dd19406f9cb', '8b921863-a6c4-5bd2-9a7e-e16a81c8926e', 'كيف نقرأ الكلمة المعروفة قراءةً سريعة؟', '[{"id":"a","text":"نقرأ آخر حرفٍ فقط"},{"id":"b","text":"ننظر إليها كاملةً ونقرؤها دفعةً واحدة"},{"id":"c","text":"نقرؤها من اليسار إلى اليمين"},{"id":"d","text":"نقرأ الحركات فقط دون الحروف"}]'::jsonb, 'b', 'الكلمة المعروفة نقرؤها كاملةً دفعةً واحدة بمجرّد النظر إليها، لا حرفًا حرفًا ولا حركةً فقط.', 2)
ON CONFLICT (id) DO UPDATE SET
