INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('92342748-4dd4-5775-b2ea-9547b79a3b2b', '8b921863-a6c4-5bd2-9a7e-e16a81c8926e', 'انظر إلى الصورة. أيّ كلمةٍ تسمّيها؟<svg viewBox="0 0 120 80" xmlns="http://www.w3.org/2000/svg"><g stroke="#1f2937" stroke-width="2"><ellipse cx="54" cy="40" rx="34" ry="19" fill="#38bdf8"/><path d="M88 40 l22 -13 l0 26 z" fill="#7dd3fc"/><circle cx="40" cy="34" r="3" fill="#1f2937" stroke="none"/><path d="M30 40 q8 6 16 0" fill="none"/></g></svg>', '[{"id":"a","text":"قِطّة"},{"id":"b","text":"عُصفور"},{"id":"c","text":"سَمَكة"},{"id":"d","text":"شَجَرة"}]'::jsonb, 'c', 'الصورة كائنٌ له جسمٌ بيضويٌّ وذيلٌ مثلّثٌ يسبح في الماء، وهو السمكة، فالكلمة المناسبة «سَمَكة».', 3)
