INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('571b4630-5d56-55f2-962b-a1bd423d218c', '8b921863-a6c4-5bd2-9a7e-e16a81c8926e', 'جملة: «القِطّةُ تشربُ الحليبَ.» ماذا تخبرنا هذه الجملة؟', '[{"id":"a","text":"أنّ الحليب يشرب القطّة"},{"id":"b","text":"أنّ القطّة تشرب الحليب"},{"id":"c","text":"أنّ القطّة تنام"},{"id":"d","text":"أنّ الكلب يأكل"}]'::jsonb, 'b', 'نقرأ الجملة من اليمين: القِطّةُ ← تشربُ ← الحليبَ، فهي تخبرنا أنّ القطّة هي التي تشرب الحليب.', 4)
