INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('f2745485-5ca4-56a5-8eec-37d59e11a13d', '61a6ccd9-f86a-57f2-bb6e-150c7605534c', 'اقرأ الكلمة «سَمَكة»، ثمّ اختر الصورة التي تناسبها.', '[{"id":"a","text":"<svg viewBox=\"0 0 120 80\" xmlns=\"http://www.w3.org/2000/svg\"><g stroke=\"#1f2937\" stroke-width=\"2\"><ellipse cx=\"54\" cy=\"40\" rx=\"34\" ry=\"19\" fill=\"#38bdf8\"/><path d=\"M88 40 l22 -13 l0 26 z\" fill=\"#7dd3fc\"/><circle cx=\"40\" cy=\"34\" r=\"3\" fill=\"#1f2937\" stroke=\"none\"/><path d=\"M30 40 q8 6 16 0\" fill=\"none\"/></g></svg>"},{"id":"b","text":"<svg viewBox=\"0 0 110 90\" xmlns=\"http://www.w3.org/2000/svg\"><g stroke=\"#1f2937\" stroke-width=\"2\"><rect x=\"48\" y=\"48\" width=\"14\" height=\"30\" fill=\"#92400e\"/><circle cx=\"55\" cy=\"34\" r=\"24\" fill=\"#22c55e\"/></g></svg>"},{"id":"c","text":"<svg viewBox=\"0 0 110 90\" xmlns=\"http://www.w3.org/2000/svg\"><g stroke=\"#1f2937\" stroke-width=\"2\"><circle cx=\"55\" cy=\"45\" r=\"22\" fill=\"#facc15\"/><path d=\"M55 13 v-8 M23 45 h-8 M87 45 h8 M55 77 v8\" stroke=\"#f59e0b\" stroke-width=\"3\"/></g></svg>"},{"id":"d","text":"<svg viewBox=\"0 0 110 90\" xmlns=\"http://www.w3.org/2000/svg\"><g stroke=\"#1f2937\" stroke-width=\"2\"><path d=\"M55 24 q-20 -6 -20 20 q0 28 20 34 q20 -6 20 -34 q0 -26 -20 -20\" fill=\"#ef4444\"/></g></svg>"}]'::jsonb, 'a', '«سَمَكة» كائنٌ يسبح في الماء له ذيلٌ، فتناسبها الصورة الأولى؛ أمّا الباقي فشجرةٌ وشمسٌ وتفّاحة.', 1)
