  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('8a461a53-9f32-5a07-ad96-a625d52034a8', '61a6ccd9-f86a-57f2-bb6e-150c7605534c', 'اقرأ جملة: «الطّفلُ يقرأُ الكِتابَ.» مَن يقرأ في الجملة؟', '[{"id":"a","text":"الكِتاب"},{"id":"b","text":"الطّفل"},{"id":"c","text":"المُعلّم"},{"id":"d","text":"لا أحد يقرأ"}]'::jsonb, 'b', 'نقرأ من اليمين: الطّفلُ ← يقرأُ ← الكِتابَ، فالذي يقرأ هو الطّفل، والكتاب هو المقروء.', 2)
