INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('84aa7f88-69c5-5bc3-9dea-45c73b852a8a', '61a6ccd9-f86a-57f2-bb6e-150c7605534c', 'كلمتان متشابهتان: «جَمَل» و«جَمال». أيّهما اسمُ الحيوان الذي يعيش في الصحراء؟', '[{"id":"a","text":"«جَمال» لأنّها أطول"},{"id":"b","text":"الكلمتان تعنيان الحيوان"},{"id":"c","text":"«جَمَل» فهي اسم الحيوان"},{"id":"d","text":"لا علاقة لأيٍّ منهما بالحيوان"}]'::jsonb, 'c', '«جَمَل» اسمُ حيوان الصحراء، أمّا «جَمال» فتعني الحُسن؛ حرفٌ واحد (الألف) يغيّر المعنى.', 3)
