INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('c5bde795-ad45-5ee7-8d01-09deb9ca8110', '61a6ccd9-f86a-57f2-bb6e-150c7605534c', 'قال طفلٌ: «الكلمتان (نَمْل) و(نَخْل) تعنيان الشيء نفسه لأنّهما متشابهتان». ما الصحيح؟', '[{"id":"a","text":"صحيح، الكلمتان تعنيان الشيء نفسه"},{"id":"b","text":"نَمْل ونَخْل كلاهما حشرة"},{"id":"c","text":"لا فرق، فالحروف لا تغيّر المعنى"},{"id":"d","text":"الخطأ الشائع؛ «نَمْل» حشرةٌ و«نَخْل» شجر التمر، حرفٌ واحد يغيّر المعنى"}]'::jsonb, 'd', 'الخطأ الشائع: ظنّ الكلمتين المتشابهتين بمعنًى واحد. «نَمْل» حشرةٌ صغيرة و«نَخْل» شجر التمر، وحرف الميم أو الخاء يغيّر المعنى كلّه.', 6)
