INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('83f39cf5-b14e-5807-9c57-39f57b5bf88f', 'de7e4b9b-336e-585a-aa39-84f2418e89c5', 'اقرأ الجملة وانظر إلى الصورة: «الطّائرُ فوقَ الشّجرةِ.» هل توافق الصورة الجملة؟<svg viewBox="0 0 120 120" xmlns="http://www.w3.org/2000/svg"><g stroke="#1f2937" stroke-width="2"><rect x="54" y="66" width="14" height="40" fill="#92400e"/><circle cx="61" cy="50" r="26" fill="#22c55e"/><ellipse cx="61" cy="18" rx="13" ry="8" fill="#3b82f6"/><path d="M74 18 l12 -5 l-4 8 Z" fill="#60a5fa"/><circle cx="52" cy="16" r="2" fill="#1f2937" stroke="none"/></g></svg>', '[{"id":"a","text":"لا، الطائر تحت الشجرة"},{"id":"b","text":"نعم، الطائر فوق الشجرة كما تقول الجملة"},{"id":"c","text":"الصورة فيها سمكة"},{"id":"d","text":"الجملة عن قطّة"}]'::jsonb, 'b', 'الصورة تُظهر طائرًا أزرق فوق شجرةٍ خضراء، وهذا يوافق الجملة «الطّائرُ فوقَ الشّجرةِ».', 1)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('96af5184-c621-5c4b-aab2-7c47b6a4899b', 'de7e4b9b-336e-585a-aa39-84f2418e89c5', 'اقرأ الكلمة «شَمْس»، ثمّ اختر الصورة التي تناسبها.', '[{"id":"a","text":"<svg viewBox=\"0 0 110 90\" xmlns=\"http://www.w3.org/2000/svg\"><g stroke=\"#1f2937\" stroke-width=\"2\"><rect x=\"48\" y=\"52\" width=\"14\" height=\"30\" fill=\"#92400e\"/><circle cx=\"55\" cy=\"36\" r=\"24\" fill=\"#22c55e\"/></g></svg>"},{"id":"b","text":"<svg viewBox=\"0 0 120 80\" xmlns=\"http://www.w3.org/2000/svg\"><g stroke=\"#1f2937\" stroke-width=\"2\"><ellipse cx=\"54\" cy=\"40\" rx=\"32\" ry=\"18\" fill=\"#38bdf8\"/><path d=\"M86 40 l22 -12 l0 24 z\" fill=\"#7dd3fc\"/><circle cx=\"40\" cy=\"35\" r=\"3\" fill=\"#1f2937\" stroke=\"none\"/></g></svg>"},{"id":"c","text":"<svg viewBox=\"0 0 110 90\" xmlns=\"http://www.w3.org/2000/svg\"><g stroke=\"#1f2937\" stroke-width=\"2\"><circle cx=\"55\" cy=\"45\" r=\"20\" fill=\"#facc15\"/><path d=\"M55 15 v-9 M55 75 v9 M25 45 h-9 M85 45 h9 M34 24 l-7 -7 M76 24 l7 -7 M34 66 l-7 7 M76 66 l7 7\" stroke=\"#f59e0b\" stroke-width=\"3\"/></g></svg>"},{"id":"d","text":"<svg viewBox=\"0 0 110 90\" xmlns=\"http://www.w3.org/2000/svg\"><g stroke=\"#1f2937\" stroke-width=\"2\"><path d=\"M55 24 q-20 -6 -20 20 q0 28 20 34 q20 -6 20 -34 q0 -26 -20 -20\" fill=\"#ef4444\"/></g></svg>"}]'::jsonb, 'c', '«شَمْس» قرصٌ أصفر تخرج منه أشعّةٌ في كلّ جهة، فتناسبها الصورة الثالثة؛ أمّا الباقي فشجرةٌ وسمكةٌ وتفّاحة.', 2)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('5535a88c-6c0d-527f-a483-f9ac7403112e', 'de7e4b9b-336e-585a-aa39-84f2418e89c5', 'جملة: «أكلَ الوَلَدُ التُّفّاحةَ، فابتسمَ.» لماذا ابتسم الولد؟', '[{"id":"a","text":"لأنّه أكل التُّفّاحة وأعجبته"},{"id":"b","text":"لأنّه لم يأكل شيئًا"},{"id":"c","text":"لأنّ التُّفّاحة أكلته"},{"id":"d","text":"الجملة لا تذكر الولد"}]'::jsonb, 'a', 'نقرأ الجملة كاملةً ونفهم السبب: الولد أكل التُّفّاحة فابتسم، أي ابتسم لأنّها أعجبته.', 3)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('de34c035-5841-5ab2-adc5-6b93987f7dba', 'de7e4b9b-336e-585a-aa39-84f2418e89c5', 'ثلاث كلماتٍ متشابهة: «حَمَل» و«جَمَل» و«جَمال». أيّها اسمُ حيوان الصحراء ذي السَّنام؟', '[{"id":"a","text":"«حَمَل» (وهو صغير الخروف)"},{"id":"b","text":"«جَمَل»"},{"id":"c","text":"«جَمال» (وهي تعني الحُسن)"},{"id":"d","text":"الثلاث كلماتٍ تعني الجَمل"}]'::jsonb, 'b', '«جَمَل» هو حيوان الصحراء ذو السَّنام، أمّا «حَمَل» فصغير الخروف و«جَمال» فالحُسن؛ حرفٌ واحد يميّز كلّ معنى.', 4)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('2cc17b82-2108-5dce-9548-3def68e4f448', 'de7e4b9b-336e-585a-aa39-84f2418e89c5', 'جملة: «لم يشربِ القِطُّ الحليبَ.» هل شرب القطُّ الحليب؟', '[{"id":"a","text":"نعم، شرب كلّ الحليب"},{"id":"b","text":"نعم، شرب نصف الحليب"},{"id":"c","text":"لا، لم يشربِ القطُّ الحليب"},{"id":"d","text":"الجملة لا تتكلّم عن القطّ"}]'::jsonb, 'c', 'كلمة «لم» تنفي الفعل؛ فالجملة «لم يشربِ القِطُّ الحليبَ» تعني أنّ القطّ لم يشرب الحليب.', 5)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('4e24f57d-066c-5317-bf7a-e6da4d8688df', 'de7e4b9b-336e-585a-aa39-84f2418e89c5', 'قال طفلٌ: «ما دامت الصورة فيها قطّةٌ فالكلمة تحتها لا بدّ أن تكون (قطّة)، حتّى لو كانت مكتوبةً (كلب)». ما الصحيح؟', '[{"id":"a","text":"الكلمة والصورة لا علاقة بينهما أبدًا"},{"id":"b","text":"صحيح، الصورة هي التي تحدّد الكلمة دائمًا"},{"id":"c","text":"نقرأ الصورة فقط ولا ننظر إلى الحروف"},{"id":"d","text":"الخطأ الشائع؛ يجب أن أقرأ الكلمة نفسها، فإن كُتب (كلب) فالكلمة (كلب) ولو خالفت الصورة"}]'::jsonb, 'd', 'الخطأ الشائع: الاكتفاء بالصورة دون قراءة الحروف. الصورة تساعد على الفهم، لكنّ الكلمة تُقرأ من حروفها؛ فإن كُتب «كلب» قرأناها «كلب» ولو خالفت الصورة.', 6)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

