  ('d803026c-3daa-5a6d-825a-cfee7fc5c8e2', 'd8f61676-66db-559b-bcf8-c4e4240d21f2', 'arabic-2eme', '📝 تدريب ⭐⭐⭐: أقرأ الكلمة والجملة (شاملة)', 3, 120, 30, 'boss', 'admin', 5)
