INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('33e3d20c-43fb-5990-b3fc-d41b19de8611', 'd803026c-3daa-5a6d-825a-cfee7fc5c8e2', 'ما أوّل خطوةٍ نقوم بها لنفهم معنى كلمةٍ لها صورة؟', '[{"id":"a","text":"نقرأ الكلمة كاملةً وننظر إلى صورتها"},{"id":"b","text":"نعدّ حروفها فقط"},{"id":"c","text":"نقرأ آخر حرفٍ فيها"},{"id":"d","text":"نقلب الكلمة من اليسار"}]'::jsonb, 'a', 'نقرأ الكلمة كاملةً ثمّ ننظر إلى صورتها لنربط بينهما ونفهم المعنى، لا أن نعدّ الحروف فقط.', 1)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
