  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('1879746a-bb81-5dca-9d51-cb503d575bfa', 'd803026c-3daa-5a6d-825a-cfee7fc5c8e2', 'انظر إلى الصورة. أيّ كلمةٍ تناسبها؟<svg viewBox="0 0 110 110" xmlns="http://www.w3.org/2000/svg"><g stroke="#1f2937" stroke-width="2"><circle cx="55" cy="42" r="16" fill="#ef4444"/><circle cx="55" cy="42" r="7" fill="#fde047"/><path d="M55 58 L55 96" stroke="#16a34a" stroke-width="3"/><path d="M55 78 q-16 -6 -20 -18 q14 0 20 10" fill="#22c55e"/><path d="M55 84 q16 -4 20 -14 q-14 -2 -20 8" fill="#22c55e"/></g></svg>', '[{"id":"a","text":"سَمَكة"},{"id":"b","text":"زَهْرة"},{"id":"c","text":"شَمْس"},{"id":"d","text":"بَيْت"}]'::jsonb, 'b', 'الصورة لها بتلاتٌ حمراء حول قلبٍ أصفر وساقٌ خضراء بورقتين، وهي الزهرة، فالكلمة المناسبة «زَهْرة».', 2)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('f6d62ae6-b235-56b7-b69c-6c4fa8c64289', 'd803026c-3daa-5a6d-825a-cfee7fc5c8e2', 'جملة: «يلعبُ الطّفلانِ بالكُرةِ.» بماذا يلعب الطّفلان؟', '[{"id":"a","text":"بالكتاب"},{"id":"b","text":"بالدّمية"},{"id":"c","text":"بالكُرة"},{"id":"d","text":"لا يلعبان بشيء"}]'::jsonb, 'c', 'نقرأ الجملة من اليمين ونفهمها: يلعبُ ← الطّفلانِ ← بالكُرةِ، فهما يلعبان بالكُرة.', 3)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('802b6c11-9f88-512f-8829-be2da56e47b9', 'd803026c-3daa-5a6d-825a-cfee7fc5c8e2', 'أيّ ترتيبٍ للكلمات يكوّن جملةً مفهومة؟', '[{"id":"a","text":"شربَ القِطُّ الحليبَ"},{"id":"b","text":"الحليبَ القِطُّ شربَ"},{"id":"c","text":"القِطُّ الحليبَ شربَ"},{"id":"d","text":"الحليبَ شربَ القِطُّ"}]'::jsonb, 'a', 'الجملة المفهومة تبدأ بالفعل ثمّ الفاعل ثمّ المفعول: «شربَ القِطُّ الحليبَ»، وهي تخبرنا بوضوحٍ مَن شرب وماذا شرب.', 4)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('1ecccde6-6d44-5dca-a882-176460be0ba5', 'd803026c-3daa-5a6d-825a-cfee7fc5c8e2', 'الكلمتان «قَلْب» و«كَلْب» متشابهتان في النّطق. أيّهما اسمُ الحيوان الذي ينبح؟', '[{"id":"a","text":"«قَلْب» (وهو العضو الذي ينبض)"},{"id":"b","text":"«كَلْب»"},{"id":"c","text":"الكلمتان تعنيان الحيوان"},{"id":"d","text":"لا واحدة منهما حيوان"}]'::jsonb, 'b', '«كَلْب» (بالكاف) هو الحيوان الذي ينبح، أمّا «قَلْب» (بالقاف) فهو العضو الذي ينبض؛ حرفٌ واحد يغيّر المعنى.', 5)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('2a25cf04-8255-562c-83b7-c92818aeec3c', 'd803026c-3daa-5a6d-825a-cfee7fc5c8e2', 'جملة: «الجَوُّ ماطرٌ، فحملَ الوَلَدُ المِظلّةَ.» لماذا حمل الولد المِظلّة؟', '[{"id":"a","text":"لأنّ الشّمس حارّة"},{"id":"b","text":"لأنّه ذاهبٌ إلى النّوم"},{"id":"c","text":"الجملة لا تذكر المطر"},{"id":"d","text":"لأنّ الجوّ ماطرٌ والمِظلّة تقيه المطر"}]'::jsonb, 'd', 'نربط جزأي الجملة: الجوّ ماطرٌ، فحمل الولد المِظلّة ليقي نفسه من المطر، فهذا هو السبب.', 6)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

