INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('fd479b64-8692-5ac6-9639-8c1718f0468b', '67063338-6624-564a-9f22-feb1c9f2eb98', 'اقرأ النصّ: «ذهبَ سامي إلى الحديقة. لعبَ بالكرة مع صديقه. ثمّ عادَ إلى البيت.» مَن البطل في القصّة؟', '[{"id":"a","text":"الصديق"},{"id":"b","text":"سامي"},{"id":"c","text":"الأمّ"},{"id":"d","text":"المعلّم"}]'::jsonb, 'b', 'النصّ يبدأ بـ«ذهبَ سامي»، فالبطل هو سامي، وهو الشخصيّة التي تتحدّث عنها القصّة.', 1)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('def3f2f7-7284-586e-8c03-a94107c9d71a', '67063338-6624-564a-9f22-feb1c9f2eb98', 'في النصّ نفسه: «ذهبَ سامي إلى الحديقة. لعبَ بالكرة مع صديقه.» أين ذهبَ سامي؟', '[{"id":"a","text":"إلى الحديقة"},{"id":"b","text":"إلى المدرسة"},{"id":"c","text":"إلى السوق"},{"id":"d","text":"إلى البحر"}]'::jsonb, 'a', 'قال النصّ «ذهبَ سامي إلى الحديقة»، فالمكان هو الحديقة، وهذا جواب سؤال: أين؟', 2)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('77aefb34-3351-54bd-9c04-3198384114e4', '67063338-6624-564a-9f22-feb1c9f2eb98', 'في النصّ نفسه: «لعبَ بالكرة مع صديقه.» بماذا لعبَ سامي؟', '[{"id":"a","text":"بالدرّاجة"},{"id":"b","text":"بالرمل"},{"id":"c","text":"بالكرة"},{"id":"d","text":"بالكتاب"}]'::jsonb, 'c', 'قال النصّ «لعبَ بالكرة»، فالجواب هو الكرة. لا نختار الدرّاجة لأنّها ليست في النصّ.', 3)
ON CONFLICT (id) DO UPDATE SET
