INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('a70b2646-7063-5ee9-bcb6-5b5747910f2d', '67063338-6624-564a-9f22-feb1c9f2eb98', 'إذا نسيتَ جواب سؤالٍ عن النصّ، ماذا تفعل؟', '[{"id":"a","text":"أُجيب بأيّ كلمةٍ بسرعة"},{"id":"b","text":"أرجع إلى النصّ وأقرأه مرّةً أخرى"},{"id":"c","text":"أخترع جوابًا من خيالي"},{"id":"d","text":"أترك السؤال فارغًا"}]'::jsonb, 'b', 'الطريقة الصحيحة أن نرجع إلى النصّ ونقرأه من جديد، لأنّ الجواب مكتوبٌ فيه.', 4)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
