INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('b8897b23-561a-5e43-8ca3-cd878b12cf3b', 'ce47204d-84bb-567c-9ec5-ccdc836e29cb', 'في النصّ نفسه: «ضحك الأصدقاء وصفّقوا له.» ماذا فعل الأصدقاء؟', '[{"id":"a","text":"ناموا مبكّرًا"},{"id":"b","text":"بكوا بحزن"},{"id":"c","text":"ضحكوا وصفّقوا"},{"id":"d","text":"خرجوا غاضبين"}]'::jsonb, 'c', 'قال النصّ «ضحك الأصدقاء وصفّقوا له»، فالحدث هو الضحك والتصفيق، وهذا جواب: ماذا فعلوا؟', 3)
