INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('5d791f11-3103-581d-ba8d-557d2d0accde', 'ce47204d-84bb-567c-9ec5-ccdc836e29cb', 'قال طفل: «الأصدقاء كانوا حزينين». ماذا نفهم حقًّا من النصّ «ضحك الأصدقاء وصفّقوا»؟', '[{"id":"a","text":"صحيح، كانوا حزينين"},{"id":"b","text":"النصّ لم يذكر شعورهم"},{"id":"c","text":"كانوا فرحين؛ لأنّهم ضحكوا وصفّقوا"},{"id":"d","text":"كانوا خائفين من الشموع"}]'::jsonb, 'c', 'الخطأ الشائع: الإجابة من الخيال لا من النصّ. الضحك والتصفيق دليل الفرح، فالأصدقاء كانوا فرحين كما يدلّ النصّ.', 6)
