  ('e11a409c-8a98-559b-b201-6f2f99a3879b', '24b2985f-ec64-5f01-aa53-eb9c935cf484', 'ما لون هذا الشكل؟<svg viewBox="0 0 70 70" xmlns="http://www.w3.org/2000/svg"><circle cx="35" cy="35" r="26" fill="#ef4444" stroke="#1f2937" stroke-width="2"/></svg>', '[{"id":"a","text":"أزرق"},{"id":"b","text":"أحمر"},{"id":"c","text":"أخضر"},{"id":"d","text":"أصفر"}]'::jsonb, 'b', 'الشكل مملوءٌ باللون الأحمر، فاسم لونه «أحمر». الأزرق والأخضر والأصفر ألوانٌ أخرى مختلفة.', 1)
