INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('5d199047-f79e-5160-b99d-04599f51b650', '3a2a220b-f47a-52eb-9cac-0e82d825cf87', 'رتّب الكلمات: [الحقيبةَ / يحملُ / التلميذُ] لتُكوّن جملةً صحيحة.', '[{"id":"a","text":"يحملُ التلميذُ الحقيبةَ."},{"id":"b","text":"الحقيبةَ التلميذُ يحملُ."},{"id":"c","text":"الحقيبةَ يحملُ التلميذُ."},{"id":"d","text":"التلميذُ الحقيبةَ يحملُ."}]'::jsonb, 'a', 'نبدأ بالفعل «يحملُ» ثمّ الفاعل «التلميذُ» ثمّ «الحقيبةَ»، فنفهم المعنى؛ أمّا الترتيبات الأخرى فمقلوبةٌ يصعب فهمها.', 3)
