INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('b94fe1e1-dbc8-51b1-b8cd-d5f16ee261ec', '3a2a220b-f47a-52eb-9cac-0e82d825cf87', 'ما الكلمة الزائدة التي يجب حذفها لتصحّ الجملة: «يلبسُ الولدُ المعطفَ المطرَ.»؟', '[{"id":"a","text":"المعطفَ"},{"id":"b","text":"يلبسُ"},{"id":"c","text":"المطرَ"},{"id":"d","text":"الولدُ"}]'::jsonb, 'c', 'الولد يلبسُ المعطفَ لا المطرَ، فنحذف «المطرَ» لتصير الجملة: «يلبسُ الولدُ المعطفَ.» وتعطي معنًى صحيحًا.', 4)
