INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('94eca388-a3b7-5f13-800b-4f166fd1759b', '469f90ff-2968-5e7c-9edc-d1559a7b0a87', 'كلمة «فَمه» تنتهي بالهاء (ه). ما الفرق بينها وبين التاء المربوطة (ة)؟', '[{"id":"a","text":"الهاء بلا نقطتين، والتاء المربوطة عليها نقطتان"},{"id":"b","text":"لا فرق بينهما"},{"id":"c","text":"الهاء عليها نقطتان والتاء المربوطة بلا نقطتين"},{"id":"d","text":"كلتاهما تُنطق تاءً"}]'::jsonb, 'a', 'نميّز بالنقطتين: التاء المربوطة (ة) عليها نقطتان، أمّا الهاء (ه) في «فَمه» فبلا نقطتين.', 4)
