INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('9386c06f-7ba5-57ed-bc63-33f21e4b9b58', '469f90ff-2968-5e7c-9edc-d1559a7b0a87', 'أيّ سطرٍ وُضعت فيه علامة الترقيم صحيحةً؟', '[{"id":"a","text":"هل تُحبّ القراءة."},{"id":"b","text":"ذهبَ الولدُ إلى المدرسةِ."},{"id":"c","text":"أين أخوك."},{"id":"d","text":"ما أروعَ البحرَ."}]'::jsonb, 'b', '«ذهبَ الولدُ إلى المدرسةِ» جملةٌ خبريّةٌ تنتهي بالنقطة (.). أمّا الأسئلة (هل، أين، متى) فتنتهي بـ«؟»، والتعجّب بـ«!».', 5)
