INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('576a5bc7-ad37-5c2e-806f-1e24c04c01ee', '4c58005f-2c50-5c5d-9f40-dfb0d3b45de7', 'أيّ مجموعةٍ كلّ كلماتها تُكتب بالتاء المربوطة (ة)؟', '[{"id":"a","text":"مَدْرَسة، تُفّاحة، قِطّة"},{"id":"b","text":"بِنت، بَيت، أُخت"},{"id":"c","text":"وَجه، فَمه، بَيت"},{"id":"d","text":"وَرْدة، بِنت، أُخت"}]'::jsonb, 'a', '«مَدْرَسة، تُفّاحة، قِطّة» كلّها ننطق آخرها هاءً عند الوقف فتُكتب بالتاء المربوطة (ة). أمّا «بِنت، بَيت، أُخت» فبالتاء المفتوحة، و«وَجه، فَمه» بالهاء.', 1)
