INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('3701bf83-1845-51e3-be49-c7a3d597e758', '4c58005f-2c50-5c5d-9f40-dfb0d3b45de7', 'أيّ جملةٍ وُضعت فيها علامة الترقيم وُضعًا صحيحًا؟', '[{"id":"a","text":"هل أكلتَ التُّفّاحةَ."},{"id":"b","text":"ما أجملَ الوَرْدةَ!"},{"id":"c","text":"ذهبَ أبي إلى العمل؟"},{"id":"d","text":"أين أُختُك!"}]'::jsonb, 'b', '«ما أجملَ الوَرْدةَ!» جملةُ تعجّبٍ فتنتهي بعلامة التعجّب (!). أمّا السؤال «هل» فيلزمه «؟»، والجملة الخبريّة «ذهبَ أبي» يلزمها «.»، والسؤال «أين» يلزمه «؟».', 2)
ON CONFLICT (id) DO UPDATE SET
