  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('4472ac12-e2ee-5da8-a077-67d523677476', '4c58005f-2c50-5c5d-9f40-dfb0d3b45de7', 'فخّ! قال طفلٌ: «كلّ كلمةٍ آخرها صوت ـه تُكتب هاءً (ه)». ما الصحيح؟', '[{"id":"a","text":"صحيح، نكتبها دائمًا هاءً (ه)"},{"id":"b","text":"الاسم المؤنّث يُكتب بالتاء المربوطة (ة) ذات النقطتين، مثل «مَدْرَسة»"},{"id":"c","text":"نكتبها دائمًا تاءً مفتوحة (ت)"},{"id":"d","text":"نكتبها ألفًا (ا)"}]'::jsonb, 'b', 'الخطأ الشائع: الخلط بين الهاء والتاء المربوطة. الاسم الذي ننطق آخره هاءً عند الوقف (مثل «مَدْرَسة») يُكتب بالتاء المربوطة (ة) ذات النقطتين، لا بالهاء.', 3)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

